/* ── SCROLL REVEAL ───────────────────────────────────────── */

document.querySelectorAll('.reveal').forEach(el => {
  new IntersectionObserver((entries, observer) => {
    if (entries[0].isIntersecting) {
      entries[0].target.classList.add('vis');
      observer.disconnect();
    }
  }, { threshold: 0.07 }).observe(el);
});


/* ── HERO STARS (coral tinted) ───────────────────────────── */

(function () {
  const canvas = document.getElementById('hero-canvas');
  const ctx    = canvas.getContext('2d');
  let W, H;

  function resize() {
    W = canvas.width  = canvas.offsetWidth;
    H = canvas.height = canvas.offsetHeight;
  }
  resize();
  window.addEventListener('resize', resize);

  const COLORS = [
    '#ff4757', '#ff6b7a', '#ff9f43', '#ffd93d',
    '#ff85a1', '#ffffff', '#ffcccc', '#ff7043', '#ffb3ba'
  ];

  const dots = Array.from({ length: 160 }, () => ({
    x     : Math.random() * 100,
    y     : Math.random() * 78,
    r     : Math.random() * 2 + 0.6,
    color : COLORS[Math.floor(Math.random() * COLORS.length)],
    alpha : Math.random() * 0.55 + 0.2,
    phase : Math.random() * Math.PI * 2,
    speed : Math.random() * 0.35 + 0.1,
    drift : Math.random() * 0.05 - 0.025
  }));

  let t = 0;

  (function draw() {
    ctx.clearRect(0, 0, W, H);
    t += 0.012;

    dots.forEach(d => {
      const x = (d.x / 100) * W;
      const y = (d.y / 100) * H;
      const a = d.alpha * (0.5 + 0.5 * Math.sin(t * d.speed + d.phase));

      ctx.beginPath();
      ctx.arc(x, y, d.r, 0, Math.PI * 2);
      ctx.fillStyle   = d.color;
      ctx.globalAlpha = a;
      ctx.fill();

      d.x += d.drift;
      if (d.x < -2)  d.x = 102;
      if (d.x > 102) d.x = -2;
    });

    ctx.globalAlpha = 1;
    requestAnimationFrame(draw);
  })();
})();


/* ── TYPING EFFECT ───────────────────────────────────────── */

const phrases = {
  fr: ['Full Stack Developer', 'Dev Web & Mobile', 'Data Enthusiast', 'Spring Boot · ReactJS · Kotlin'],
  en: ['Full Stack Developer', 'Web & Mobile Developer', 'Data Enthusiast', 'Spring Boot · ReactJS · Kotlin']
};

let lang = 'fr';
let pi   = 0;
let ci   = 0;
let del  = false;

const typingEl = document.getElementById('typEl');

function type() {
  const full    = phrases[lang][pi];
  const current = del ? full.substring(0, ci--) : full.substring(0, ci++);

  typingEl.innerHTML = current + '<span style="color:var(--coral);animation:cpulse 1s step-end infinite;">|</span>';

  let speed = del ? 42 : 72;
  if (!del && ci > full.length) { speed = 1900; del = true; }
  if (del  && ci < 0)           { del = false; pi = (pi + 1) % phrases[lang].length; ci = 0; speed = 260; }

  setTimeout(type, speed);
}
type();


/* ── DRAG TO SCROLL (projects) ───────────────────────────── */

const trackWrap = document.querySelector('.proj-track-wrap');
let isDown = false;
let startX, scrollLeft;

trackWrap.addEventListener('mousedown', e => {
  isDown     = true;
  startX     = e.pageX - trackWrap.offsetLeft;
  scrollLeft = trackWrap.scrollLeft;
  trackWrap.style.userSelect = 'none';
});

['mouseleave', 'mouseup'].forEach(ev => {
  trackWrap.addEventListener(ev, () => {
    isDown = false;
    trackWrap.style.userSelect = '';
  });
});

trackWrap.addEventListener('mousemove', e => {
  if (!isDown) return;
  e.preventDefault();
  trackWrap.scrollLeft = scrollLeft - (e.pageX - trackWrap.offsetLeft - startX) * 1.2;
});


