/* ── POPUP ───────────────────────────────────────────────── */

let curSlide    = 0;
let curProjData = null;

function openPopup(idx) {
  const p = PROJ[lang][idx];
  curProjData = p;
  curSlide    = 0;

  document.getElementById('popTopTitle').textContent = p.name;
  document.getElementById('popType').textContent     = p.type;
  document.getElementById('popName').textContent     = p.name;
  document.getElementById('popDesc').textContent     = p.desc;

  const feat = document.getElementById('popFeat');
  feat.style.display = p.featured ? '' : 'none';
  if (p.featured) feat.textContent = p.featured;

  document.getElementById('popTechs').innerHTML =
    p.techs.map(t => `<span class="tc">${t}</span>`).join('');

  const linksEl = document.getElementById('popLinks');
  if (p.links.length) {
    linksEl.innerHTML = p.links
      .map(l => `<a href="${l.url}" target="_blank" class="pl${l.live ? ' live' : ''}">${l.label}</a>`)
      .join('');
  } else {
    linksEl.innerHTML = `<span style="font-family:var(--fc);font-size:.7rem;color:var(--muted)">
      ${lang === 'fr' ? 'Projet interne — pas de dépôt public' : 'Internal project — no public repository'}
    </span>`;
  }

  buildGallery(p.images);
  document.getElementById('popupOverlay').classList.add('open');
  document.body.style.overflow = 'hidden';
}

function buildGallery(images) {
  const track = document.getElementById('slidesTrack');
  const dots  = document.getElementById('galDots');
  track.innerHTML = '';
  dots.innerHTML  = '';

  images.forEach((img, i) => {
    const slide = document.createElement('div');
    slide.className = 'slide';

    if (img.src) {
      const el = document.createElement('img');
      el.setAttribute('src', img.src);
      el.setAttribute('alt', img.alt || '');
      slide.appendChild(el);
    } else {
      const ico  = document.createElement('span');
      ico.className   = 'ico';
      ico.textContent = img.placeholder;
      const lbl  = document.createElement('span');
      lbl.style.cssText = 'font-family:var(--fc);font-size:.6rem;letter-spacing:.1em;text-transform:uppercase;';
      lbl.textContent   = img.label;
      slide.appendChild(ico);
      slide.appendChild(lbl);
    }

    track.appendChild(slide);

    const dot = document.createElement('div');
    dot.className = 'gal-dot' + (i === 0 ? ' on' : '');
    dot.onclick   = () => goSlide(i);
    dots.appendChild(dot);
  });

  goSlide(0);
}

function goSlide(n) {
  if (!curProjData) return;
  curSlide = Math.max(0, Math.min(n, curProjData.images.length - 1));
  document.getElementById('slidesTrack').style.transform = `translateX(-${curSlide * 100}%)`;
  document.querySelectorAll('.gal-dot').forEach((d, i) => d.classList.toggle('on', i === curSlide));
}

function galPrev() { goSlide(curSlide - 1); }
function galNext() { goSlide(curSlide + 1); }

function closePopup() {
  document.getElementById('popupOverlay').classList.remove('open');
  document.body.style.overflow = '';
}

function closeOnBg(e) {
  if (e.target === document.getElementById('popupOverlay')) closePopup();
}

document.addEventListener('keydown', e => {
  if (e.key === 'Escape')     closePopup();
  if (e.key === 'ArrowLeft')  galPrev();
  if (e.key === 'ArrowRight') galNext();
});


