function setLang(l) {
  lang = l;
  document.getElementById('bFr').classList.toggle('on', l === 'fr');
  document.getElementById('bEn').classList.toggle('on', l === 'en');

  const c = T[l];

  // Simple text updates
  [
    'hBadge', 'hBtn1', 'hBtn2', 'hScroll',
    'photoRole', 'bioText', 'bioText2', 'bioText3', 'bioAmbitionText',
    'skOpB', 'skOpF', 'skOpD', 'skOpAI', 'skOpT',
    'e1hook', 'e2hook', 'e3hook',
    'aLbl', 'aTitle',
    'st1', 'st2', 'st3', 'st4',
    'skLbl', 'skTitle', 'catB', 'catF', 'catD', 'catAI', 'catT',
    'exLbl', 'exTitle',
    'e1p', 'e1r', 'e1b', 'e1c',
    'e2p', 'e2r', 'e2c',
    'e3p', 'e3r', 'e3c',
    'prLbl', 'prTitle', 'prSub', 'fb1',
    'pt1', 'pt2', 'pt3',
    'pd1s', 'pd2s', 'pd3s',
    'ctaCard1', 'ctaCard2', 'ctaCard3',
    'pp1', 'pp2', 'pp3', 'dragHint',
    'coLbl', 'coTitle', 'cml', 'cph', 'cloc',
    'ctaH', 'ctaB',
    'ftTagline', 'ftBadge', 'fcNav', 'fcProj', 'fcStack',
    'fn1', 'fn2', 'fn3', 'fn4', 'fn5',
    'ftc', 'ftMade',
    'na1', 'na2', 'na3', 'na4', 'na5'
  ].forEach(id => {
    const el = document.getElementById(id);
    if (el && c[id] !== undefined) el.textContent = c[id];
  });

  // HTML updates (contain <strong> tags)
  ['hDesc', 'aP1', 'aP2', 'aP3', 'ctaP'].forEach(id => {
    const el = document.getElementById(id);
    if (el && c[id] !== undefined) el.innerHTML = c[id];
  });

  // Mobile nav
  ['na1', 'na2', 'na3', 'na4', 'na5'].forEach((id, i) => {
    const mn = document.getElementById('ma' + (i + 1));
    if (mn && c[id]) mn.textContent = c[id];
  });

  // Experience task lists
  [1, 2, 3].forEach(n => {
    const ul = document.getElementById('e' + n + 't');
    if (ul) ul.innerHTML = tasks[l]['e' + n].map(t => `<li>${t}</li>`).join('');
  });

  // Popup labels
  document.getElementById('popTechTitle').textContent = l === 'fr' ? 'Stack technique' : 'Tech stack';
  document.getElementById('popLinkTitle').textContent = l === 'fr' ? 'Liens' : 'Links';
  document.getElementById('popCloseBtn').textContent  = l === 'fr' ? '✕ Fermer' : '✕ Close';
  
}